 1→package com.fsck.k9.preferences.upgrader
 2→
 3→import app.k9mail.legacy.account.Account.FolderMode
 4→import com.fsck.k9.mail.FolderClass
 5→import com.fsck.k9.preferences.CombinedSettingsUpgrader
 6→import com.fsck.k9.preferences.InternalSettingsMap
 7→import com.fsck.k9.preferences.ValidatedSettings
 8→
 9→class CombinedSettingsUpgraderTo100 : CombinedSettingsUpgrader {
10→    override fun upgrade(account: ValidatedSettings.Account): ValidatedSettings.Account {
11→        val folderDisplayMode = account.settings["folderDisplayMode"] as? FolderMode ?: FolderMode.NONE
12→
13→        val newFolders = account.folders.map { folder ->
14→            val newFolderSettings = folder.settings.toMutableMap().apply {
15→                this["visible"] = folder.isVisible(folderDisplayMode)
16→            }
17→
18→            folder.copy(settings = newFolderSettings)
19→        }
20→
21→        return account.copy(folders = newFolders)
22→    }
23→
24→    private fun ValidatedSettings.Folder.isVisible(folderDisplayMode: FolderMode): Boolean {
25→        val displayClass = getEffectiveDisplayClass(settings)
26→
27→        return when (folderDisplayMode) {
28→            FolderMode.NONE -> {
29→                false
30→            }
31→
32→            FolderMode.ALL -> {
33→                true
34→            }
35→
36→            FolderMode.FIRST_CLASS -> {
37→                displayClass == FolderClass.FIRST_CLASS
38→            }
39→
40→            FolderMode.FIRST_AND_SECOND_CLASS -> {
41→                displayClass == FolderClass.FIRST_CLASS || displayClass == FolderClass.SECOND_CLASS
42→            }
43→
44→            FolderMode.NOT_SECOND_CLASS -> {
45→                displayClass != FolderClass.SECOND_CLASS
46→            }
47→        }
48→    }
49→
50→    private fun getEffectiveDisplayClass(folderSettings: InternalSettingsMap): FolderClass {
51→        return folderSettings.getFolderClass("displayMode").takeIf { it != FolderClass.INHERITED }
52→            ?: FolderClass.NO_CLASS
53→    }
54→
55→    private fun InternalSettingsMap.getFolderClass(key: String): FolderClass {
56→        return this[key] as? FolderClass ?: FolderClass.NO_CLASS
57→    }
58→}
