  1→package com.fsck.k9.preferences
  2→
  3→import com.fsck.k9.preferences.SettingsFile.Account
  4→import com.fsck.k9.preferences.SettingsFile.Contents
  5→import com.fsck.k9.preferences.SettingsFile.Folder
  6→import com.fsck.k9.preferences.SettingsFile.Identity
  7→import com.fsck.k9.preferences.SettingsFile.Server
  8→import java.io.InputStream
  9→import java.io.InputStreamReader
 10→import java.util.UUID
 11→import org.xmlpull.v1.XmlPullParser
 12→import org.xmlpull.v1.XmlPullParserException
 13→import org.xmlpull.v1.XmlPullParserFactory
 14→import timber.log.Timber
 15→
 16→/**
 17→ * Parser for K-9 Mail's settings file format.
 18→ */
 19→internal class SettingsFileParser {
 20→    @Throws(SettingsImportExportException::class)
 21→    fun parseSettings(inputStream: InputStream): Contents {
 22→        try {
 23→            return XmlSettingsParser(inputStream).parse()
 24→        } catch (e: XmlPullParserException) {
 25→            throw SettingsImportExportException("Error parsing settings XML", e)
 26→        } catch (e: SettingsParserException) {
 27→            throw SettingsImportExportException("Error parsing settings XML", e)
 28→        }
 29→    }
 30→}
 31→
 32→@Suppress("TooManyFunctions")
 33→private class XmlSettingsParser(
 34→    private val inputStream: InputStream,
 35→) {
 36→    private val pullParser: XmlPullParser = XmlPullParserFactory.newInstance().newPullParser().apply {
 37→        setInput(InputStreamReader(inputStream))
 38→    }
 39→
 40→    fun parse(): Contents {
 41→        var contents: Contents? = null
 42→        do {
 43→            val eventType = pullParser.next()
 44→
 45→            if (eventType == XmlPullParser.START_TAG) {
 46→                when (pullParser.name) {
 47→                    SettingsExporter.ROOT_ELEMENT -> {
 48→                        contents = readRoot()
 49→                    }
 50→                    else -> {
 51→                        skipElement()
 52→                    }
 53→                }
 54→            }
 55→        } while (eventType != XmlPullParser.END_DOCUMENT)
 56→
 57→        if (contents == null) {
 58→            parserError("Missing '${SettingsExporter.ROOT_ELEMENT}' element")
 59→        }
 60→
 61→        return contents
 62→    }
 63→
 64→    private fun readRoot(): Contents {
 65→        var generalSettings: SettingsMap? = null
 66→        var accounts: List<Account>? = null
 67→
 68→        val fileFormatVersion = readFileFormatVersion()
 69→        if (fileFormatVersion != SettingsExporter.FILE_FORMAT_VERSION) {
 70→            parserError("Unsupported file format version: $fileFormatVersion")
 71→        }
 72→
 73→        val contentVersion = readContentVersion()
 74→
 75→        readElement { eventType ->
 76→            if (eventType == XmlPullParser.START_TAG) {
 77→                when (pullParser.name) {
 78→                    SettingsExporter.GLOBAL_ELEMENT -> {
 79→                        if (generalSettings == null) {
 80→                            generalSettings = readGlobalSettings()
 81→                        } else {
 82→                            Timber.w("More than one '${SettingsExporter.GLOBAL_ELEMENT}' element!")
 83→                            skipElement()
 84→                        }
 85→                    }
 86→                    SettingsExporter.ACCOUNTS_ELEMENT -> {
 87→                        if (accounts == null) {
 88→                            accounts = readAccounts()
 89→                        } else {
 90→                            Timber.w("More than one '${SettingsExporter.ACCOUNTS_ELEMENT}' element!")
 91→                            skipElement()
 92→                        }
 93→                    }
 94→                    else -> {
 95→                        skipElement()
 96→                    }
 97→                }
 98→            }
 99→        }
100→
101→        return Contents(contentVersion, generalSettings, accounts.orEmpty())
102→    }
103→
104→    private fun readFileFormatVersion(): Int {
105→        val versionString = readAttribute(SettingsExporter.FILE_FORMAT_ATTRIBUTE)
106→        return versionString.toIntOrNull()
107→            ?: parserError("Invalid file format version: $versionString")
108→    }
109→
110→    private fun readContentVersion(): Int {
111→        val versionString = readAttribute(SettingsExporter.VERSION_ATTRIBUTE)
112→        return versionString.toIntOrNull()?.takeIf { it > 0 }
113→            ?: parserError("Invalid content version: $versionString")
114→    }
115→
116→    private fun readGlobalSettings(): SettingsMap? {
117→        return readSettingsContainer()
118→    }
119→
120→    private fun readSettingsContainer(): SettingsMap? {
121→        val settings = mutableMapOf<String, String>()
122→
123→        readElement { eventType ->
124→            if (eventType == XmlPullParser.START_TAG) {
125→                when (pullParser.name) {
126→                    SettingsExporter.VALUE_ELEMENT -> {
127→                        val key = readAttribute(SettingsExporter.KEY_ATTRIBUTE)
128→                        val value = readText()
129→
130→                        if (settings.containsKey(key)) {
131→                            Timber.w("Already read key \"%s\". Ignoring value \"%s\"", key, value)
132→                        } else {
133→                            settings[key] = value
134→                        }
135→                    }
136→                    else -> {
137→                        skipElement()
138→                    }
139→                }
140→            }
141→        }
142→
143→        return settings.takeIf { it.isNotEmpty() }
144→    }
145→
146→    private fun readAccounts(): List<Account> {
147→        val accounts = mutableListOf<Account>()
148→
149→        readElement { eventType ->
150→            if (eventType == XmlPullParser.START_TAG) {
151→                when (pullParser.name) {
152→                    SettingsExporter.ACCOUNT_ELEMENT -> {
153→                        val account = readAccount()
154→
155→                        if (account == null) {
156→                            // Do nothing - readAccount() already logged a message
157→                        } else if (accounts.any { it.uuid == account.uuid }) {
158→                            Timber.w("Duplicate account entries with UUID %s. Ignoring!", account.uuid)
159→                        } else {
160→                            accounts.add(account)
161→                        }
162→                    }
163→                    else -> {
164→                        skipElement()
165→                    }
166→                }
167→            }
168→        }
169→
170→        return accounts
171→    }
172→
173→    private fun readAccount(): Account? {
174→        val uuid = readUuid()
175→        if (uuid == null) {
176→            skipElement()
177→            return null
178→        }
179→
180→        var name: String? = null
181→        var incoming: Server? = null
182→        var outgoing: Server? = null
183→        var settings: SettingsMap? = null
184→        var identities: List<Identity>? = null
185→        var folders: List<Folder>? = null
186→
187→        readElement { eventType ->
188→            if (eventType == XmlPullParser.START_TAG) {
189→                when (pullParser.name) {
190→                    SettingsExporter.NAME_ELEMENT -> {
191→                        name = readText()
192→                    }
193→                    SettingsExporter.INCOMING_SERVER_ELEMENT -> {
194→                        incoming = readServerSettings()
195→                    }
196→                    SettingsExporter.OUTGOING_SERVER_ELEMENT -> {
197→                        outgoing = readServerSettings()
198→                    }
199→                    SettingsExporter.SETTINGS_ELEMENT -> {
200→                        settings = readSettingsContainer()
201→                    }
202→                    SettingsExporter.IDENTITIES_ELEMENT -> {
203→                        identities = readIdentities()
204→                    }
205→                    SettingsExporter.FOLDERS_ELEMENT -> {
206→                        folders = readFolders()
207→                    }
208→                    else -> {
209→                        skipElement()
210→                    }
211→                }
212→            }
213→        }
214→
215→        // If we couldn't find an account name use the UUID
216→        if (name == null) {
217→            name = uuid
218→        }
219→
220→        return Account(uuid, name, incoming, outgoing, settings, identities, folders)
221→    }
222→
223→    private fun readUuid(): String? {
224→        val uuid = pullParser.getAttributeValue(null, SettingsExporter.UUID_ATTRIBUTE)
225→
226→        try {
227→            UUID.fromString(uuid)
228→        } catch (e: IllegalArgumentException) {
229→            Timber.w(e, "Invalid account UUID: %s", uuid)
230→            return null
231→        }
232→
233→        return uuid
234→    }
235→
236→    private fun readServerSettings(): Server {
237→        var host: String? = null
238→        var port: String? = null
239→        var connectionSecurity: String? = null
240→        var authenticationType: String? = null
241→        var username: String? = null
242→        var password: String? = null
243→        var clientCertificateAlias: String? = null
244→        var extras: SettingsMap? = null
245→
246→        val type = pullParser.getAttributeValue(null, SettingsExporter.TYPE_ATTRIBUTE)
247→
248→        readElement { eventType ->
249→            if (eventType == XmlPullParser.START_TAG) {
250→                when (pullParser.name) {
251→                    SettingsExporter.HOST_ELEMENT -> {
252→                        host = readText()
253→                    }
254→                    SettingsExporter.PORT_ELEMENT -> {
255→                        port = readText()
256→                    }
257→                    SettingsExporter.CONNECTION_SECURITY_ELEMENT -> {
258→                        connectionSecurity = readText()
259→                    }
260→                    SettingsExporter.AUTHENTICATION_TYPE_ELEMENT -> {
261→                        authenticationType = readText()
262→                    }
263→                    SettingsExporter.USERNAME_ELEMENT -> {
264→                        username = readText()
265→                    }
266→                    SettingsExporter.CLIENT_CERTIFICATE_ALIAS_ELEMENT -> {
267→                        clientCertificateAlias = readText()
268→                    }
269→                    SettingsExporter.PASSWORD_ELEMENT -> {
270→                        password = readText()
271→                    }
272→                    SettingsExporter.EXTRA_ELEMENT -> {
273→                        extras = readSettingsContainer()
274→                    }
275→                    else -> {
276→                        skipElement()
277→                    }
278→                }
279→            }
