import app.k9mail.legacy.account.Account.SpecialFolderSelection

internal class AccountSettingsUpgrader(
    private val identitySettingsUpgrader: IdentitySettingsUpgrader,
    private val folderSettingsUpgrader: FolderSettingsUpgrader,
    private val serverSettingsUpgrader: ServerSettingsUpgrader,
    private val latestVersion: Int = Settings.VERSION,
    private val settingsDescriptions: SettingsDescriptions = AccountSettingsDescriptions.SETTINGS,
    private val upgraders: Map<Int, SettingsUpgrader> = AccountSettingsDescriptions.UPGRADERS,
    private val combinedUpgraders: Map<Int, CombinedSettingsUpgraderFactory> = CombinedSettingsUpgraders.UPGRADERS,
) {

    fun upgrade(contentVersion: Int, account: ValidatedSettings.Account): ValidatedSettings.Account {
        val upgradedAccount = if (contentVersion == latestVersion) {
            account
        } else {
            performVersionUpgrades(contentVersion, account)
        }

        // Ensure folder selections are set to MANUAL when folder names are present.
        // This is necessary to ensure imported folder assignments are used instead of auto-detection.
        return fixFolderSelections(upgradedAccount)
    }

    private fun performVersionUpgrades(
        contentVersion: Int,
        account: ValidatedSettings.Account,
    ): ValidatedSettings.Account {
        val relevantCombinedUpgraderVersions = combinedUpgraders.keys.asSequence()
            .filter { it > contentVersion }
            .toSortedSet()

        var currentAccount = account
        var currentVersion = contentVersion
        for (version in relevantCombinedUpgraderVersions) {
            val toVersion = version - 1
            currentAccount = upgradeToVersion(toVersion, currentVersion, currentAccount)

            val combinedUpgrader = combinedUpgraders[version]!!.invoke()
            currentAccount = combinedUpgrader.upgrade(currentAccount)

            currentAccount = upgradeToVersion(version, toVersion, currentAccount)
            currentVersion = version
        }

        return upgradeToVersion(toVersion = latestVersion, contentVersion = currentVersion, currentAccount)
    }

    private fun fixFolderSelections(account: ValidatedSettings.Account): ValidatedSettings.Account {
        val settings = account.settings.toMutableMap()
        var changed = false

        changed = fixFolderSelection(settings, "archiveFolderName", "archiveFolderSelection") || changed
        changed = fixFolderSelection(settings, "draftsFolderName", "draftsFolderSelection") || changed
        changed = fixFolderSelection(settings, "sentFolderName", "sentFolderSelection") || changed
        changed = fixFolderSelection(settings, "spamFolderName", "spamFolderSelection") || changed
        changed = fixFolderSelection(settings, "trashFolderName", "trashFolderSelection") || changed

        return if (changed) {
            account.copy(settings = settings)
        } else {
            account
        }
    }

    private fun fixFolderSelection(
        settings: MutableMap<String, Any?>,
        folderNameKey: String,
        folderSelectionKey: String,
    ): Boolean {
        val folderName = settings[folderNameKey] as? String
        val folderSelection = settings[folderSelectionKey]

        // If a folder name is present and selection is AUTOMATIC, change it to MANUAL
        // so the imported folder assignment is used instead of auto-detection.
        if (!folderName.isNullOrEmpty() && folderSelection == SpecialFolderSelection.AUTOMATIC) {
            settings[folderSelectionKey] = SpecialFolderSelection.MANUAL
            return true
        }
        return false
    }"}

{"file_path": "/project/legacy/core/src/test/java/com/fsck/k9/preferences/FolderSelectionImportTest.kt", "content": "package com.fsck.k9.preferences

import app.k9mail.legacy.account.Account.SpecialFolderSelection
import assertk.assertThat
import assertk.assertions.isEqualTo
import kotlin.test.Test

/**
 * Tests for folder selection import handling.
 *
 * Verifies that folder selections are correctly set to MANUAL when folder names are present,
 * ensuring imported folder assignments are used instead of auto-detection.
 */
class FolderSelectionImportTest {

    @Test
    fun `AccountSettingsUpgraderTo54 should set folder selection to MANUAL when folder name is present`() {
        val upgrader = com.fsck.k9.preferences.upgrader.AccountSettingsUpgraderTo54()
        val settings = mutableMapOf<String, Any>(
            "archiveFolderName" to "Archive",
            "draftsFolderName" to "Drafts",
            "sentFolderName" to "Sent",
            "spamFolderName" to "Spam",
            "trashFolderName" to "Trash",
        )

        upgrader.upgrade(settings)

        assertThat(settings["archiveFolderSelection"]).isEqualTo("MANUAL")
        assertThat(settings["draftsFolderSelection"]).isEqualTo("MANUAL")
        assertThat(settings["sentFolderSelection"]).isEqualTo("MANUAL")
        assertThat(settings["spamFolderSelection"]).isEqualTo("MANUAL")
        assertThat(settings["trashFolderSelection"]).isEqualTo("MANUAL")
    }

    @Test
    fun `AccountSettingsUpgraderTo54 should not set folder selection when folder name is null`() {
        val upgrader = com.fsck.k9.preferences.upgrader.AccountSettingsUpgraderTo54()
        val settings = mutableMapOf<String, Any>(
            "archiveFolderName" to "Archive", // Only archive has a name
        )

        upgrader.upgrade(settings)

        assertThat(settings["archiveFolderSelection"]).isEqualTo("MANUAL")
        assertThat(settings.containsKey("draftsFolderSelection")).isEqualTo(false)
        assertThat(settings.containsKey("sentFolderSelection")).isEqualTo(false)
        assertThat(settings.containsKey("spamFolderSelection")).isEqualTo(false)
        assertThat(settings.containsKey("trashFolderSelection")).isEqualTo(false)
    }

    @Test
    fun `AccountSettingsUpgraderTo54 should not set folder selection when folder name is empty`() {
        val upgrader = com.fsck.k9.preferences.upgrader.AccountSettingsUpgraderTo54()
        val settings = mutableMapOf<String, Any>(
            "archiveFolderName" to "",
            "draftsFolderName" to "",
        )

        upgrader.upgrade(settings)

        assertThat(settings.containsKey("archiveFolderSelection")).isEqualTo(false)
        assertThat(settings.containsKey("draftsFolderSelection")).isEqualTo(false)
    }

    @Test
    fun `AccountSettingsUpgrader should fix folder selections for imports at current version`() {
        val accountSettingsUpgrader = createAccountSettingsUpgrader()

        val account = ValidatedSettings.Account(
            uuid = "test-uuid",
            name = "Test Account",
            incoming = createServer(),
            outgoing = createServer(),
            settings = mapOf(
                "archiveFolderName" to "Archive",
                "archiveFolderSelection" to SpecialFolderSelection.AUTOMATIC, // This should be changed to MANUAL
                "draftsFolderName" to "Drafts",
                "draftsFolderSelection" to SpecialFolderSelection.MANUAL, // Already MANUAL, should stay MANUAL
                "sentFolderName" to null, // No folder name, selection should stay AUTOMATIC
                "sentFolderSelection" to SpecialFolderSelection.AUTOMATIC,
            ),
            identities = emptyList(),
            folders = emptyList(),
        )

        // Upgrade with contentVersion = latestVersion (no version-specific upgrades should run)
        val result = accountSettingsUpgrader.upgrade(Settings.VERSION, account)

        assertThat(result.settings["archiveFolderSelection"]).isEqualTo(SpecialFolderSelection.MANUAL)
        assertThat(result.settings["draftsFolderSelection"]).isEqualTo(SpecialFolderSelection.MANUAL)
        assertThat(result.settings["sentFolderSelection"]).isEqualTo(SpecialFolderSelection.AUTOMATIC)
    }

    @Test
    fun `AccountSettingsUpgrader should not change folder selection when folder name is absent`() {
        val accountSettingsUpgrader = createAccountSettingsUpgrader()

        val account = ValidatedSettings.Account(
            uuid = "test-uuid",
            name = "Test Account",
            incoming = createServer(),
            outgoing = createServer(),
            settings = mapOf(
                "archiveFolderSelection" to SpecialFolderSelection.AUTOMATIC,
            ),
            identities = emptyList(),
            folders = emptyList(),
        )

        val result = accountSettingsUpgrader.upgrade(Settings.VERSION, account)

        assertThat(result.settings["archiveFolderSelection"]).isEqualTo(SpecialFolderSelection.AUTOMATIC)
    }

    private fun createAccountSettingsUpgrader(): AccountSettingsUpgrader {
        return AccountSettingsUpgrader(
            identitySettingsUpgrader = IdentitySettingsUpgrader(
